 50	            ? [{ name: t('Logical Used Capacity'), id: Metrics.LOGICAL }]
 51	            : [
 52	                {
 53	                  name: t('Physical vs. Logical used capacity'),
 54	                  id: Metrics.PHY_VS_LOG,
