146	      ref={toggleRef}
147	      onClick={() => setServiceTypeDropdown(!isOpenServiceTypeDropdown)}
148	      isExpanded={isOpenServiceTypeDropdown}
149	      className="nb-data-consumption-card__dropdown-item--margin nb-data-consumption-card__dropdown-item"
150	    >
151	      {selectedService
152	        ? t('Type: {{selectedService}}', { selectedService })
153	        : t('Select Service Type')}
154	    </MenuToggle>
155	  );
156	
157	  return (
158	    <div className="nb-data-consumption-card__dropdown">
159	      {isRgwSupported && isMcgSupported && (
160	        <Select
161	          id="service-type-select"
162	          isOpen={isOpenServiceTypeDropdown}
163	          onOpenChange={setServiceTypeDropdown}
164	          onSelect={onSelectServiceDropdown}
165	          selected={selectedService}
166	          toggle={serviceTypeToggle}
167	          aria-label={t('Break By Dropdown')}
168	        >
169	          {serviceDropdownItems}
170	        </Select>
171	      )}
172	      <Select
