175	        onSelect={onSelectComboDropdown}
176	        toggle={comboToggle}
177	        onOpenChange={setComboDropdown}
178	        popperProps={{
179	          position: 'right',
180	        }}
181	      >
182	        {comboDropdownItems}
183	      </Select>
184	    </div>
185	  );
186	};
